#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int zeros=0, ones=0, x;
        for(int i=0;i<N;i++){
            scanf("%d", &x);
            if(x==0) zeros++; else ones++;
        }
        int ans = zeros<ones?zeros:ones;
        printf("%d\n", ans);
    }
    return 0;
}

