const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  let zeros = 0;
  for (let i = 0; i < N; i++) {
    if (input[idx++] === 0) zeros++;
  }
  const ones = N - zeros;
  outputs.push(String(Math.min(zeros, ones)));
}
